const Sequelize = require('sequelize');
module.exports = function (sequelize, DataTypes) {
  return sequelize.define('divisionCode', {
    divCode_id: {
      autoIncrement: true,
      autoIncrementIdentity: true,
      type: DataTypes.INTEGER,
      allowNull: false,
      primaryKey: true
    },
    divCode_code: {
      type: DataTypes.STRING,
      allowNull: false
    },
    division_name: {
      type: DataTypes.STRING(50),
      allowNull: false
    },
    company_name_fk: {
      type: DataTypes.STRING,
      allowNull: true
    },
    external_divisoncode: {
      type: DataTypes.STRING,
      allowNull: false
    },
    is_divcode_active: {
      type: DataTypes.BOOLEAN,
      allowNull: true
    }
  }, {
    sequelize,
    tableName: 'divisionCode',
    schema: process.env.schema,
    timestamps: false,
    indexes: [
      {
        name: "DivisionCode_pkey",
        unique: true,
        fields: [
          { name: "divCode_id" },
        ]
      },
    ]
  });
};
