// archive/active tab split independently of the global RFQItem.rfqItem_archive flag,
// so one vendor archiving a stale quote never hides the item from Sourcing or other
// factories. Mixed-case identifier MUST be quoted (see §11 / SYS-002).
sequelize.query(`ALTER TABLE ${schema}"RFQVendor" ADD COLUMN IF NOT EXISTS "RFQVendor_archived" BOOLEAN DEFAULT false`)

