// ── Buyer Target → Buyer Margin % (Scenario 2) ─────────────────────────────
// The salesman types a target $ price into `{type}_buyer_target`; we report the
// gross margin that price yields into `{type}_buyer_margin`. Reuses the exact
// Scenario-2 math already used by the set…SellPrice functions (getMargin), but
// reads/writes the dedicated buyer_* fields so the sourcing team's real quote is
// untouched. Stores a real number (parseFloat) into the numeric DOUBLE column.
// See designflow-frontend/docs/rfq-buyer-margin-plan.md.
BUYER_MARGIN_TYPES = [
  { type: 'gen_fob',  incoterm: 'fob',  royalty: 'gen_fob_royalty' },
  { type: 'gen_mddp', incoterm: 'mddp', royalty: 'gen_fob_royalty' },
  { type: 'gen_poe',  incoterm: 'poe',  royalty: 'gen_fob_royalty' },
  { type: 'gen_whse', incoterm: 'whse', royalty: 'gen_fob_royalty' },
  { type: 'lic_fob',  incoterm: 'fob',  royalty: 'lic_fob_royalty' },
  { type: 'lic_mddp', incoterm: 'mddp', royalty: 'lic_mddp_royalty' },
  { type: 'lic_poe',  incoterm: 'poe',  royalty: 'lic_poe_royalty' },
  { type: 'lic_whse', incoterm: 'whse', royalty: 'lic_whse_royalty' },
];

getBuyerCostBasis(incoterm, params, colHeaders) {
  const d = (colId) => params.data[this.getMasterFiledName(colId, colHeaders)];
  switch (incoterm) {
    case 'fob':
      return this.getFobTotalCost(d('fob_cost'), d('agent'));
    case 'mddp':
      return this.getMddpTotalCost(d('fob_cost'), d('agent'), d('duty_rate')?.title, params.data.duty_rate_dollar_amount);
    case 'poe':
      return this.getPoeTotalCost(d('fob_cost'), d('agent'), d('duty_rate')?.title, d('freight'), params.data.duty_rate_dollar_amount);
    case 'whse':
      return this.getWhseTotalCost(d('fob_cost'), d('agent'), d('duty_rate')?.title, d('freight'), params.data['whsecost'], d('cbm_pc'), params.data.duty_rate_dollar_amount);
    default:
      return 0;
  }
}

setBuyerMargin(cfg, params, colHeaders) {
  const targetField = this.getMasterFiledName(cfg.type + '_buyer_target', colHeaders);
  const marginField = this.getMasterFiledName(cfg.type + '_buyer_margin', colHeaders);
  // Columns absent (e.g. user lacks the toggle) → nothing to compute.
  if (!targetField || !marginField) return;

  const target = params.data[targetField];
  if (target === null || target === undefined || target === '' || isNaN(parseFloat(target))) {
    params.data[marginField] = null;
    return;
  }
  const royalty = params.data[this.getMasterFiledName(cfg.royalty, colHeaders)];
  const logistics = params.data[this.getMasterFiledName('logistics_load', colHeaders)];
  const dilution = parseFloat(params.data[this.getMasterFiledName('dilution', colHeaders)]);
  // margin excluded from the deduction here — we are solving FOR the margin.
  const deduction = this.getDeduction(royalty, 0, logistics, dilution);
  const netSellPrice = (parseFloat(target) * parseFloat(deduction)).toFixed(2);
  const costBasis = this.getBuyerCostBasis(cfg.incoterm, params, colHeaders);
  const margin = this.getMargin(netSellPrice, costBasis, target);
  // Store a real number into the numeric DOUBLE column (getMargin returns a string).
  params.data[marginField] = (margin === null || margin === undefined || isNaN(parseFloat(margin)))
    ? null
    : parseFloat(margin);
}

recalculate_Buyer_Margins(params, colHeaders) {
  try {
    for (const cfg of this.BUYER_MARGIN_TYPES) {
      this.setBuyerMargin(cfg, params, colHeaders);
    }
  } catch (e) {
    console.error('[recalculate_Buyer_Margins] error:', e);
  }
}

