import { rfqEquation } from './equation';

/**
 * Buyer Target → Buyer Margin % (Scenario 2) tests.
 *
 * colHeaders maps colId → field; params.data is keyed by field. For these tests we
 * set field === colId so the data keys are just the colIds. duty_rate is read as
 * `.title` (matches the real grid shape), and whsecost / duty_rate_dollar_amount are
 * read directly off params.data.
 */
describe('rfqEquation buyer margin (Scenario 2)', () => {
  let eq: rfqEquation;

  beforeEach(() => {
    eq = new rfqEquation();
  });

  // Build colHeaders for the colIds we use, field === colId.
  const headersFor = (colIds: string[]) => colIds.map((c) => ({ colId: c, field: c }));

  const baseColIds = [
    'fob_cost', 'agent', 'duty_rate', 'freight', 'cbm_pc',
    'logistics_load', 'dilution',
    'gen_fob_royalty', 'lic_fob_royalty', 'lic_mddp_royalty', 'lic_poe_royalty', 'lic_whse_royalty',
  ];

  const makeParams = (data: any) => ({ data });

  it('computes the documented Lic mDDP example → 30%', () => {
    // cost basis (mddp) = 4.00 (fob 4, agent 0, duty 0, dutyDollar 0)
    // royalty 12, dilution 5, logistics 3, target 8 → deduction 0.80 → net 6.40
    // margin = (6.40 - 4.00) / 8.00 * 100 = 30
    const colHeaders = headersFor([...baseColIds, 'lic_mddp_buyer_target', 'lic_mddp_buyer_margin']);
    const params = makeParams({
      fob_cost: 4, agent: 0, duty_rate: { title: 0 }, duty_rate_dollar_amount: 0,
      logistics_load: 3, dilution: 5, lic_mddp_royalty: 12,
      lic_mddp_buyer_target: 8,
    });
    eq.setBuyerMargin({ type: 'lic_mddp', incoterm: 'mddp', royalty: 'lic_mddp_royalty' }, params, colHeaders);
    expect(params.data['lic_mddp_buyer_margin']).toBeCloseTo(30, 4);
  });

  it('computes a Gen FOB margin (royalty 0)', () => {
    // fob cost = 5, target 10, no royalty/dilution/logistics → deduction 1 → net 10
    // margin = (10 - 5) / 10 * 100 = 50
    const colHeaders = headersFor([...baseColIds, 'gen_fob_buyer_target', 'gen_fob_buyer_margin']);
    const params = makeParams({
      fob_cost: 5, agent: 0, logistics_load: 0, dilution: 0, gen_fob_royalty: 0,
      gen_fob_buyer_target: 10,
    });
    eq.setBuyerMargin({ type: 'gen_fob', incoterm: 'fob', royalty: 'gen_fob_royalty' }, params, colHeaders);
    expect(params.data['gen_fob_buyer_margin']).toBeCloseTo(50, 4);
  });

  it('stores a real number, not a string', () => {
    const colHeaders = headersFor([...baseColIds, 'gen_fob_buyer_target', 'gen_fob_buyer_margin']);
