getAllRFQItem() {
  // Set loading state immediately to prevent "No Rows To Show" from appearing
  if (this.gridApi) {
    this.gridApi.setGridOption('loading', true);
  }

  this.itemService.getAllItem({ status: this.currentUrl, divisionCode: this.selectedDivisionCode, divisionStatus: this.selectedDivisionCodeStatus, highlightedItem: this.highlightedItem, filterd_rfq: this.filterd_rfq })
    .subscribe(async (data: any) => {
      // 1️⃣ Load column headers from config file
      let colHeaders = [...RFQ_COLUMN_HEADERS_CONFIG.columnDefs];

      // 2️⃣ Filter columns based on user role
      colHeaders = this.filterColumnsByRole(colHeaders, this.role);

      this.colHeaders = colHeaders;
      window['colHeaders'] = this.colHeaders;

      for (var i = 0; colHeaders.length > i; i++) {
        // The 8 "Price for Sales" columns: currency-formatted, plus a snapshot tooltip
        // (duty rate + container price at the time the cell was populated). The renderer
        // sets a native `title`, so suppress the shared AG tooltip on these columns to
        // avoid a second (truncation-gated) tooltip.
        if (PRICE_SALES_COL_IDS.includes(colHeaders[i].colId)) {
          colHeaders[i]['valueFormatter'] = this.currencyFormatter;
          colHeaders[i]['cellRenderer'] = 'priceSalesSnapshotRenderer';
          colHeaders[i]["tooltipField"] = '';
          colHeaders[i]["tooltipComponent"] = "customTooltip";
          continue;
        }

        colHeaders[i]["tooltipField"] = colHeaders[i].field !== "Picture" ? colHeaders[i].field : '',
          colHeaders[i]["tooltipComponent"] = "customTooltip"
        if (colHeaders[i].colId == 'pic') {
          colHeaders[i].cellRenderer = 'imageEditor'
          colHeaders[i].cellStyle = params => params.value ? { 'text-align': '-webkit-center' } : null
          colHeaders[i].editable = false
          colHeaders[i].suppressNoteActions = true
        } else if (colHeaders[i].colId == "quantity") {
          let col_name = colHeaders[i].field;
          colHeaders[i]['cellDataType'] = false
          colHeaders[i].valueSetter = params => {
            let vendorRes = params.data[this.getMasterFiledName('res')].split('/')
            if (parseInt(vendorRes[vendorRes.length - 1]) == 0 || params.data[col_name] == null) {
              params.data[col_name] = params.newValue;
              return true;

