private loadInitialMetadata(): void {
  forkJoin({
    role: this.itemService.verifyRole().pipe(catchError(() => of(null))),
    company: this.itemService.getCompanyCode().pipe(catchError(() => of([]))),
    status: this.itemService.getRFQItemStatus().pipe(catchError(() => of([]))),
    rfqGroup: this.itemService.getRFQGroup().pipe(catchError(() => of([]))),
    customers: this.itemService.getCustomers().pipe(catchError(() => of([]))),
    delivery: this.itemService.getDeliveryLocation().pipe(catchError(() => of([]))),
    steps: this.itemService.getRFQStep().pipe(catchError(() => of([]))),
    licenses: this.itemService.getLicenseList().pipe(catchError(() => of([]))),
    cbm: this.itemService.getCBM().pipe(catchError(() => of([]))),
  }).subscribe((res: any) => {
    // Order matters inside this synchronous block:
    // 1) role first — prepareDivisionStatus() and getAllRFQItem() column-filtering read this.role
    this.applyRole(res.role);
    // 2) company code sets selectedDivisionCode/divisionCode (needed by afterMetadataReady)
    if (Array.isArray(res.company) && res.company.length) {
      this.handleCompanyCode(res.company);
    }
    // 3) statuses + derived division status (needs role)
    this.statusList = res.status || [];
    this.prepareDivisionStatus(res.status || []);
    // 4) remaining independent reference lists
    this.applyRFQGroups(res.rfqGroup || []);
    this.customerList = res.customers || [];
    this.deliveryLocationList = res.delivery || [];
    this.applyRFQSteps(res.steps || []);
    this.applyLicenseList(res.licenses || []); // populates licenseRateMap BEFORE rows are processed
    this.applyCBM(res.cbm || []);
    // 5) metadata ready → load the grid rows
    if (this.selectedDivisionCode && this.selectedDivisionCodeStatus) {
      this.afterMetadataReady();
    }
  });
}

