// ── Buyer Target / Buyer Margin % row-level division gating ──────────────────
// RFQ rows carry the division as the `division_name` string in `Div` (e.g.
// "Spruce non-Lic", "Spruce Lic", "POP Lic"); it may be a raw string (loaded) or
// a `{title}` object (after edit). Match on the name, NOT numeric ids.

/** Lowercased division_name for a row, from the `Div` field. */
private getRowDivisionName(data: any): string {
  const div = data?.['Div'];
  if (!div) return '';
  const s = (typeof div === 'object') ? (div.title ?? '') : div;
  return String(s).toLowerCase();
}

/** True for Spruce Lic or Spruce non-Lic rows. */
private isSpruceRow(data: any): boolean {
  return this.getRowDivisionName(data).includes('spruce');
}

/** True for POP (Lic) rows. */
private isPopRow(data: any): boolean {
  return this.getRowDivisionName(data).includes('pop');
}

/** In feature scope = Spruce or POP. Other divisions (e.g. factory-import "Gen,Lic") are out. */
private isBuyerScopeRow(data: any): boolean {
  return this.isSpruceRow(data) || this.isPopRow(data);
}

/**
 * Whether the Buyer Margin % VALUE may be shown for this row+user:
 *  - admin: Spruce or POP  - toggled salesman (e.g. Adam): Spruce only (POP stays blank).
 */
private canSeeBuyerMarginValue(data: any): boolean {
  if (!this.canSeeBuyerCols) return false;
  if (this.role === 'admin') return this.isBuyerScopeRow(data);
  return this.isSpruceRow(data);
}

