RoleService.getUserRolePermissions = async (userId) => {
    // Fetch data from RolePermissions including Roles and UIElements
    const rolePermissions = await sql.RolePermissions.findAll({
      logging: console.log,
      where: {
        UserId: userId, // Ensure UserId matches
        Access: true // Ensure Access is true
      },
      include: [
        {
          model: sql.Roles,
          as: 'Role', // Ensure alias matches model association
          attributes: ['Id', 'Name']
        },
        {
          model: sql.UIElements,
          as: 'UIElement', // Ensure alias matches model association
          attributes: ['Id', 'Name', 'Type', 'ParentId']
        }
      ],
      order: [['Id', 'DESC']]
    });

    // Apply the mapping function to flatten the result
    return rolePermissions.map(permission => ({
      Id: permission.Id,
      RoleId: permission.RoleId,
      RoleName: permission.Role?.Name || null, // Flattened role name
      UserId: permission.UserId,
      ElementId: permission.ElementId,
      ElementName: permission.UIElement?.Name || null, // Flattened UI element name
      ElementType: permission.UIElement?.Type || null, // Flattened UI element type
      ParentElementId: permission.UIElement?.ParentId || null, // Flattened UI element parentid
      Access: permission.Access
    }));
  };

module.exports = RoleService;

