/**
 * Buyer Target / Buyer Margin % — row-level division gating (pure helpers).
 *
 * RFQ rows carry their division as the `division_name` string under the `Div` field
 * (e.g. "Spruce non-Lic", "Spruce Lic", "POP Lic"). It may arrive as a raw string
 * (freshly loaded) or a `{ title }` object (after inline edit). Factory-import rows can
 * carry combined codes like "Gen,Lic" — those are out of scope. Match on the NAME, not
 * numeric division ids (those are the item-master `div_code_fk` used on other screens).
 *
 * See designflow-frontend/docs/rfq-buyer-margin-plan.md §4c.
 */

/** Lowercased division_name for a row, from the `Div` field ('' when absent). */
export function getRowDivisionName(data: any): string {
  const div = data?.['Div'];
  if (!div) return '';
  const s = (typeof div === 'object') ? (div.title ?? '') : div;
  return String(s).toLowerCase();
}

/** True for Spruce Lic or Spruce non-Lic rows. */
export function isSpruceRow(data: any): boolean {
  return getRowDivisionName(data).includes('spruce');
}

/** True for POP (Lic) rows. */
export function isPopRow(data: any): boolean {
  return getRowDivisionName(data).includes('pop');
}

/** In feature scope = Spruce or POP. Anything else (e.g. "Gen,Lic", null) is out of scope. */
export function isBuyerScopeRow(data: any): boolean {
  return isSpruceRow(data) || isPopRow(data);
}

/**
 * Whether the Buyer Margin % VALUE may be shown for this row + user:
 *  - admin: Spruce or POP
 *  - toggled non-admin salesman (e.g. Adam Dweck): Spruce only (POP stays blank)
 *  - anyone without the toggle: never (columns are already hidden upstream)
 */
export function canSeeBuyerMarginValue(opts: { role: string | undefined; canSeeBuyerCols: boolean; data: any }): boolean {
  const { role, canSeeBuyerCols, data } = opts;
  if (!canSeeBuyerCols) return false;
  if (role === 'admin') return isBuyerScopeRow(data);
  return isSpruceRow(data);
}

