import { describe, it, expect } from '@jest/globals';
import {
  getRowDivisionName, isSpruceRow, isPopRow, isBuyerScopeRow, canSeeBuyerMarginValue,
} from './buyer-margin-visibility';

describe('buyer-margin-visibility', () => {
  describe('getRowDivisionName', () => {
    it('reads a raw string Div (as loaded)', () => {
      expect(getRowDivisionName({ Div: 'Spruce non-Lic' })).toBe('spruce non-lic');
    });
    it('reads a { title } Div (after edit)', () => {
      expect(getRowDivisionName({ Div: { title: 'POP Lic' } })).toBe('pop lic');
    });
    it('returns empty string for missing/null Div', () => {
      expect(getRowDivisionName({})).toBe('');
      expect(getRowDivisionName({ Div: null })).toBe('');
      expect(getRowDivisionName(null)).toBe('');
    });
  });

  describe('division predicates', () => {
    it('treats both Spruce variants as Spruce', () => {
      expect(isSpruceRow({ Div: 'Spruce Lic' })).toBe(true);
      expect(isSpruceRow({ Div: 'Spruce non-Lic' })).toBe(true);
      expect(isSpruceRow({ Div: { title: 'Spruce non-Lic' } })).toBe(true);
    });
    it('treats POP Lic as POP, not Spruce', () => {
      expect(isPopRow({ Div: 'POP Lic' })).toBe(true);
      expect(isSpruceRow({ Div: 'POP Lic' })).toBe(false);
